package echo

import (
	"net/http"
	"testing"

	"github.com/stretchr/testify/assert"
)

func TestRouterTrailingSlashDebug(t *testing.T) {
	e := New()
	r := e.router

	// Route order matters for the tree structure
	r.Add(http.MethodGet, "/users", func(c Context) error {
		c.Set("path", c.Path())
		c.Set("param", c.Param("*"))
		return nil
	})
	r.Add(http.MethodGet, "/users/*", func(c Context) error {
		c.Set("path", c.Path())
		c.Set("param", c.Param("*"))
		return nil
	})

	// Test 1: /users should work
	c := e.NewContext(nil, nil).(*context)
	r.Find(http.MethodGet, "/users", c)
	assert.NotNil(t, c.handler, "/users should have a handler")
	if c.handler != nil {
		c.handler(c)
		t.Logf("Path for /users: %v", c.Get("path"))
		t.Logf("Param for /users: %v", c.Get("param"))
	}

	// Test 2: /users/ - THIS IS THE FAILING CASE
	c = e.NewContext(nil, nil).(*context)
	r.Find(http.MethodGet, "/users/", c)
	t.Logf("Handler for /users/: %v", c.handler)
	t.Logf("Path for /users/: %v", c.Get("path"))
	if c.handler != nil {
		c.handler(c)
		t.Logf("Param for /users/: %v", c.Get("param"))
		assert.Equal(t, "/users/*", c.Get("path"))
		assert.Equal(t, "", c.Get("param"))
	} else {
		t.Fatalf("No handler found for /users/!")
	}

	// Test 3: /users/something
	c = e.NewContext(nil, nil).(*context)
	r.Find(http.MethodGet, "/users/something", c)
	assert.NotNil(t, c.handler, "/users/something should have a handler")
	if c.handler != nil {
		c.handler(c)
		t.Logf("Path for /users/something: %v", c.Get("path"))
		t.Logf("Param for /users/something: %v", c.Get("param"))
		assert.Equal(t, "/users/*", c.Get("path"))
		assert.Equal(t, "something", c.Get("param"))
	}
}
