package echo

import (
	"net/http"
	"testing"

	"github.com/stretchr/testify/assert"
)

func TestRouterTrailingSlashNotFound(t *testing.T) {
	e := New()
	r := e.router

	foundCount := 0
	notFoundCount := 0

	// Route
	r.Add(http.MethodGet, "/users", func(c Context) error {
		foundCount++
		c.Set("path", c.Path())
		return nil
	})
	r.Add(http.MethodGet, "/users/*", func(c Context) error {
		foundCount++
		c.Set("path", c.Path())
		return nil
	})

	// Test: /users/ - THIS IS THE FAILING CASE
	c := e.NewContext(nil, nil).(*context)
	r.Find(http.MethodGet, "/users/", c)

	// Check if it's NotFoundHandler
	if c.handler == NotFoundHandler {
		t.Error("/users/ returned NotFoundHandler, this is the bug!")
		notFoundCount++
	} else if c.handler != nil {
		c.handler(c)
		t.Logf("Path for /users/: %v, found=%d", c.Get("path"), foundCount)
		assert.Equal(t, "/users/*", c.Get("path"), "/users/ should match /users/*")
		assert.Equal(t, "", c.Param("*"))
	} else {
		t.Error("/users/ returned nil handler")
	}

	assert.Equal(t, 0, notFoundCount, "should not have NotFoundHandler")
	assert.Equal(t, 1, foundCount, "should have found exactly one route")
}
EOF
