		handlersMatch := map[string]HandlerFunc{
			"articles": articlesHandler,
			"products": productsHandler,
			"articles/*": articlesWildcardHandler,
		}

		actualHandlerPtr := reflect.ValueOf(c.handler).Pointer()

		for name, h := range handlersMatch {
			if reflect.ValueOf(h).Pointer() == actualHandlerPtr {
				t.Logf("Found handler: %s", name)
				c.handler(c)
				t.Logf("Matched value: %v", c.Get("matched"))
				break
			}
		}
	}
}
EOF
