// Check which handler was found
func TestCheckWhichHandler(t *testing.T) {
	e := New()
	r := e.router

	artHandler := func(c Context) error { c.Set("which", "articles"); return nil }
	prodHandler := func(c Context) error { c.Set("which", "products"); return nil }
	artWildHandler := func(c Context) error { c.Set("which", "articles/*"); return nil }

	r.Add(http.MethodGet, "/articles", artHandler)
	r.Add(http.MethodGet, "/products", prodHandler)
	r.Add(http.MethodGet, "/articles/*", artWildHandler)

	c := e.NewContext(nil, nil).(*context)
	r.Find(http.MethodGet, "/articles/", c)

	if c.handler == nil {
		t.Fatal("No handler")
	}

	c.handler(c)
	which := c.Get("which")
	t.Logf("Handler found: %v, path=%v", which, c.path)
	assert.Equal(t, "/articles/*", which, "should have found /articles/* handler")
	assert.Equal(t, "/articles/*", c.path, "path should be /articles/*")
}

